inImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Sprinkler System', 'Comprehensive sprinkler system for uniform lawn and garden watering. Adjustable sprinkler heads cover large areas efficiently. Perfect for automated garden irrigation. Saves time and reduces water waste.', 1, '62.png', 280, 6340, 0.0, 36.9, 0, 1, 7);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Hose Pipe', 'Durable hose pipe for garden watering and cleaning. Weather-resistant material lasts for years. Available in various lengths for different needs. Essential for flexible garden watering.', 1, '63.png', 2.5, 3595, 0.0, 50.44, 0, 6, 13);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Drip Emitters', 'Precision drip emitters for accurate water delivery to individual plants. Prevents water runoff and reduces waste. Perfect for drip irrigation system setup. Each emitter delivers consistent water flow.', 1, '64.png', 15, 4692, 0.0, 30.79, 0, 4, 4);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Sprinkler Head', 'Adjustable sprinkler head for customized water coverage. Various spray patterns for different watering needs. Easy to adjust for optimal coverage. Essential component for sprinkler systems.', 0, '65.png', 40, 8252, 0.0, 58.85, 0, 4, 18);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Irrigation Timer', 'Automatic irrigation timer for convenient scheduled watering. Saves time with automated watering cycles. Water-resistant design for outdoor use. Perfect for busy gardeners who want consistent watering.', 1, '66.png', 180, 8671, 0.0, 26.46, 0, 5, 13);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity,