) values ('PVC Pipes', 'Durable PVC pipes for irrigation and water systems. Resistant to chemicals and corrosion. Easy installation and maintenance. Essential component for irrigation system setup.', 1, '72.png', 3.5, 7501, 0.0, 69.29, 0, 1, 8);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Irrigation Connectors', 'Quality irrigation connectors for joining hoses and pipes securely. Leak-proof connections ensure efficient water delivery. Available in various sizes for different system needs. Essential fittings for irrigation systems.', 1, '73.png', 12, 267, 0.0, 58.21, 0, 7, 17);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Garden Soaker Hose', 'Porous soaker hose for slow deep watering of plants. Water soaks directly into soil minimizing waste. Perfect for vegetable gardens and flower beds. Efficient water delivery system.', 1, '74.png', 2.8, 2800, 0.0, 41.16, 0, 2, 16);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Automatic Valve', 'Automatic valve for controlling water flow in irrigation systems. Timer-compatible for scheduled watering. Reliable durable construction. Convenient component for automated irrigation.', 0, '75.png', 95, 8161, 0.0, 45.64, 0, 1, 18);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Tomato Seedling', 'Healthy tomato seedling ready for transplanting to garden beds. Young plant with strong root system. Adapted to local growing conditions. Jump-start your tomato harvest with quality seedlings.', 0, '76.png', 15, 9654, 0.0, 73.41, 0, 7, 3);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Strawberry Plant', 'Productive strawberry plant ready to produce delicious berries. Disease-resistant variety for successful growing. Established root system for better transplant success. Fresh fruit production within weeks.', 0, '77.png', 25, 4055, 0.0, 83.49, 0, 1, 12);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Lettuce Plant', 'Fresh lettuce plant for immediate salad greens production. Young plant ready for harvesting in weeks. Tender flavorful leaves for culinary use. Perfect for quick garden establishment.', 0, '78.png', 12, 8303, 0.0, 21.91, 0, 6, 4);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Basil Plant', 'Fragrant basil plant for fresh herb harvesting. Healthy plant with vigorous growth. Perfect for Italian cooking and herbal teas. Productive plant provides months of fresh herbs.', 0, '79.png', 20, 5447, 0.0, 41.91, 0, 1, 14);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Mint Plant', 'Vigorous mint plant for fresh herbal beverages and cooking. Productive plant ensures continuous harvest. Strong growth habit provides abundant leaves. Perennial plant offers years of production.', 0, '80.png', 18, 6158, 0.0, 25.64, 0, 6, 9);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Pepper Seedling', 'Healthy pepper seedling for growing colorful bell peppers or hot peppers. Young plant with developed root system. Ready for transplanting to garden beds. High-yielding pepper production.', 0, '81.png', 18, 7394, 0.0, 10.99, 0, 2, 11);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Cucumber Seedling', 'Vigorous cucumber seedling for quick fruit production. Healthy young plant with strong roots. Ready for garden transplanting. Early harvest of fresh crispy cucumbers.', 0, '82.png', 16, 2947, 0.0, 61.97, 0, 3, 7);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Rose Plant', 'Beautiful rose plant for ornamental gardening and fresh flowers. Healthy plant with multiple blooms. Various colors available for garden color schemes. Brings elegance and fragrance to gardens.', 0, '83.png', 45, 6158, 0.0, 86.7, 0, 3, 4);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Jasmine Plant', 'Fragrant jasmine plant for aromatic gardens and outdoor decor. Beautiful white flowers with intoxicating fragrance. Vigorous growth for quick coverage. Adds romance to garden spaces.', 1, '84.png', 50, 3254, 0.0, 9.84, 0, 4, 10);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Orchid Plant', 'Exotic orchid plant for indoor gardening and plant collections. Beautiful flowers with long blooming period. Thrives in bright indirect light. Stunning addition to home decor.', 0, '85.png', 65, 9233, 0.0, 72.22, 0, 6, 8);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Sunflower Seedling', 'Cheerful sunflower seedling for bright garden displays. Healthy young plant ready for garden planting. Produces large stunning yellow flowers. Attracts pollinators and birds to gardens.', 1, '86.png', 12, 4974, 0.0, 21.96, 0, 4, 2);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Marigold Seedling', 'Colorful marigold seedling for vibrant garden displays. Healthy plant ready for transplanting. Produces abundant bright flowers throughout season. Natural pest deterrent for vegetable gardens.', 0, '87.png', 14, 9209, 0.0, 77.93, 0, 1, 15);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Eggplant Seedling', 'Productive eggplant seedling for growing glossy purple fruits. Healthy young plant ready for garden beds. Begins fruiting within weeks after transplanting. Excellent vegetable for culinary use.', 0, '88.png', 17, 8823, 0.0, 32.36, 0, 7, 7);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Pumpkin Plant', 'Large-fruited pumpkin plant for fall harvests. Vigorous vines produce substantial orange pumpkins. Suitable for decoration and culinary use. Fun crop for fall gardens.', 1, '89.png', 20, 548, 0.0, 63.93, 0, 6, 6);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Lemon Tree Seedling', 'Citrus lemon tree seedling for growing fresh lemons at home. Young tree with developing root system. Begins producing fruit within 2-3 years. Fresh lemons for culinary and beverage use.', 1, '90.png', 55, 3042, 0.0, 87.07, 0, 1, 14);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Peat Moss', 'Light airy peat moss for improving soil texture and water retention. Ideal for container gardening and seed starting. Acidic pH perfect for acid-loving plants. Essential soil amendment for quality growing medium.', 1, '91.png', 140, 8337, 0.0, 42.37, 0, 7, 5);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Coco Peat', 'Sustainable coco peat alternative to peat moss from coconut husks. Excellent water retention and drainage properties. Renewable resource for environmentally conscious gardeners. Perfect for container gardening.', 1, '92.png', 130, 2775, 0.0, 92.18, 0, 4, 9);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Garden Soil', 'Premium garden soil blend for bed preparation and filling. Balanced composition of organic matter and minerals. Ready to use for immediate planting. Contains beneficial microorganisms for healthy growth.', 0, '93.png', 40, 9801, 0.0, 37.95, 0, 1, 2);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Vermicompost', 'Nutrient-rich vermicompost from worm castings for superior plant nutrition. Improves soil structure and water-holding capacity. Beneficial microorganisms enhance plant health. Organic amendment for sustainable gardening.', 0, '94.png', 90, 1480, 0.0, 55.26, 0, 5, 14);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Perlite', 'Light perlite for improving soil aeration and drainage. Prevents soil compaction in container gardens. Reduces overall soil weight for easier handling. Essential component for quality potting mixes.', 1, '95.png', 160, 280, 0.0, 93.29, 0, 1, 2);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Pumice Stone', 'Volcanic pumice stone for excellent drainage in potting mixes. Lightweight alternative to perlite with similar benefits. Improves aeration for healthy root development. Ideal for succulent and orchid growing.', 0, '96.png', 150, 9291, 0.0, 97.16, 0, 7, 7);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Sand Soil Mix', 'Well-balanced sand and soil mixture for various gardening applications. Improves drainage in clay soils. Suitable for seed starting and container gardening. Affordable soil amendment option.', 1, '97.png', 35, 7985, 0.0, 81.0, 0, 5, 1);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Compost Soil Mix', 'Rich compost blended with garden soil for enhanced fertility. Perfect for vegetable gardens and flower beds. Provides immediate nutrients for plant growth. Superior mix for garden establishment.', 1, '98.png', 50, 7769, 0.0, 12.81, 0, 2, 5);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Loam Soil', 'Premium loam soil with balanced clay sand and silt content. Ideal natural soil for vegetable gardening. Excellent water-holding and drainage properties. Perfect for raised beds and garden beds.', 0, '99.png', 38, 7802, 0.0, 66.01, 0, 5, 17);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Clay Soil', 'Natural clay soil for areas needing good water retention. Excellent base soil with nutrient content. Benefits from compost amendments for improved drainage. Suitable for water-loving plants.', 1, '100.png', 32, 1489, 0.0, 53.97, 0, 1, 8);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Organic Soil', 'Premium organic soil enriched with natural materials. Perfect for organic gardening and sustainable agriculture. Free from synthetic chemicals and additives. Supports healthy plant growth naturally.', 1, '101.png', 85, 8580, 0.0, 39.42, 0, 6, 12);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Potting Mix', 'Specialized potting mix for container gardening and houseplants. Lightweight formula ensures proper drainage. Balanced nutrients support container plant health. Ideal for seeds seedlings and flowering plants.', 1, '102.png', 75, 5766, 0.0, 62.27, 0, 3, 5);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Raised Bed Soil', 'Quality soil specifically formulated for raised garden beds. Optimized texture for excellent root penetration. Good drainage prevents waterlogging. Ready to use for immediate bed filling.', 1, '103.png', 55, 9226, 0.0, 24.48, 0, 2, 13);\r\ninsert into products (Name, Description, Status, MainImg, Price, Quantity, Rate, Discount, Traffic, CategoryId, BrandId) values ('Mulch', 'Natural mulch for soil protection and moisture conservation. Prevents weed growth and regulates soil temperature. Gradually decomposes adding organic matter to soil. Essential for low-maintenance gardening.', 0, '104.png', 45, 2484, 0.0, 0.25, 0, 5, 4);\r\n");
